# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Prevent insecure universal link handling.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler: UIApplicationDelegate {
    func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIAppleMusicPlayerRestorationFinishedContexts]) -> Void) -> Bool {
        guard let url = userActivity.webpageURL else { return false }
        
        if !url.scheme?.hasPrefix("https") ?? true || !url.host?.contains("myapp.com") ?? true {
            print("Insecure universal link detected. Ignoring.")
            return false
        }
        
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        guard let token = components?.queryItems?.first(where: { $0.name == "token" })?.value else { return false }
        
        // Navigate to password reset screen with token
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let vc = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController")
        vc.token = token
        self.window?.rootViewController?.present(vc, animated: true, completion: nil)
        
        return true
    }
}

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        // Register for universal links
        let urlTypes = [URLType.init(urlScheme: "https://myapp.com")]
        application.registerForRemoteNotifications()
        application.registerForRemoteNotificationTypes([.alert])
        
        return true
    }
